/*
 * Crash-Proof taskpane.js
 */

// 1. Immediately bind the button click events as soon as the DOM is ready.
// This ensures your UI is ALWAYS active and responsive.
if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", initUI);
} else {
    initUI();
}

function initUI() {
    const settingsBtn = document.getElementById("settingsBtn");
    const tabsToggle = document.getElementById("toggle-sheet-tabs");

    if (settingsBtn) {
        settingsBtn.addEventListener("click", toggleSettingsMenu);
        console.log("Settings button listener bound successfully.");
    }

    if (tabsToggle) {
        tabsToggle.addEventListener("change", function () {
            toggleExcelSheetTabs(tabsToggle.checked);
        });
        console.log("Worksheet tabs toggle listener bound successfully.");
    }
}

// 2. Safely initialize Office-specific features ONLY when Office is fully ready.
Office.onReady(function (info) {
    if (info.host === Office.HostType.Excel) {
        console.log("Office.js is fully ready.");
        
        // Quietly sync the checkbox state with Excel's window settings
        const tabsToggle = document.getElementById("toggle-sheet-tabs");
        if (tabsToggle) {
            syncInitialTabsState(tabsToggle);
        }
    }
});

/**
 * Menu UI Toggler (Strictly local DOM manipulation - cannot crash)
 */
function toggleSettingsMenu() {
    const menu = document.getElementById("settingsMenu");
    if (menu) {
        menu.classList.toggle("hidden");
        console.log("Settings menu toggled.");
    } else {
        console.warn("Could not find element with id 'settingsMenu'");
    }
}

/**
 * Safely query the workbook's visual tab state.
 * If this fails, it is caught in a block and won't crash your buttons.
 */
async function syncInitialTabsState(checkboxElement) {
    try {
        await Excel.run(async (context) => {
            const activeWindow = context.workbook.getActiveWindow();
            activeWindow.load("showWorkbookTabs");
            await context.sync();
            
            checkboxElement.checked = activeWindow.showWorkbookTabs;
            console.log("Workbook tabs status successfully synced: ", activeWindow.showWorkbookTabs);
        });
    } catch (error) {
        // If it's a web platform or a startup conflict, catch the error quietly
        console.warn("Could not sync Excel window state on boot: ", error.message);
    }
}

/**
 * Send show/hide command to the Excel Window Instance
 */
async function toggleExcelSheetTabs(isVisible) {
    try {
        if (Office.context.requirements.isSetSupported("ExcelApiDesktop", "1.1")) {
            await Excel.run(async (context) => {
                const activeWindow = context.workbook.getActiveWindow();
                activeWindow.showWorkbookTabs = isVisible;
                await context.sync();
                console.log("Excel sheet tab visibility changed to: ", isVisible);
            });
        } else {
            console.warn("This platform does not support modifying workbook window tab visibility.");
        }
    } catch (error) {
        console.error("Error setting sheet tab visibility: ", error);
    }
}